import fs from 'fs'
import { RepositoryIndex, SearchResult } from './types/index.js'
import { indexRepository } from './indexer/indexer.js'
import { searchFiles } from './retrieval/searcher.js'
import { expandGraphFromSeeds } from './graph/graphBuilder.js'

let currentIndex: RepositoryIndex | null = null

export function buildIndex(repositoryPath: string): RepositoryIndex {
  console.log(`\n=== Indexing Repository: ${repositoryPath} ===\n`)

  const startTime = Date.now()
  currentIndex = indexRepository(repositoryPath)
  const duration = Date.now() - startTime

  console.log('\n=== Index Complete ===')
  console.log(`Total Files: ${currentIndex.statistics.totalFiles}`)
  console.log(`Total Lines: ${currentIndex.statistics.totalLines}`)
  console.log(`Total Symbols: ${currentIndex.statistics.symbolCount}`)
  console.log(`Graph Edges: ${currentIndex.graph.edges.length}`)
  console.log(`Duration: ${duration}ms`)

  console.log('\nLanguage Distribution:')
  const sortedLangs = Object.entries(currentIndex.statistics.languageDistribution)
    .sort((a, b) => b[1] - a[1])
  sortedLangs.forEach(([lang, count]) => {
    console.log(`  ${lang}: ${count} files`)
  })

  return currentIndex
}

export function saveIndex(outputPath: string = 'repository_index.json'): void {
  if (!currentIndex) {
    throw new Error('No index available. Call buildIndex() first.')
  }

  console.log(`\nSaving index to ${outputPath}...`)
  fs.writeFileSync(outputPath, JSON.stringify(currentIndex, null, 2))
  console.log('Index saved successfully.')
}

export function loadIndex(inputPath: string = 'repository_index.json'): RepositoryIndex {
  console.log(`Loading index from ${inputPath}...`)
  const data = fs.readFileSync(inputPath, 'utf-8')
  currentIndex = JSON.parse(data)
  console.log('Index loaded successfully.')
  return currentIndex!
}

export function search(query: string, topK: number = 10): SearchResult[] {
  if (!currentIndex) {
    throw new Error('No index available. Call buildIndex() or loadIndex() first.')
  }

  console.log(`\n=== Searching for: "${query}" ===\n`)

  const results = searchFiles(query, currentIndex.files)
  const topResults = results.slice(0, topK)

  console.log(`Found ${results.length} matching files. Showing top ${topResults.length}:\n`)

  topResults.forEach((result, index) => {
    console.log(`${index + 1}. ${result.file.path} (score: ${result.score})`)
    console.log(`   Language: ${result.file.language}`)
    console.log(`   Symbols: ${result.file.symbols.length}`)
    console.log(`   Reasons: ${result.matchReasons.slice(0, 3).join(', ')}`)
    console.log()
  })

  return topResults
}

export function searchWithGraph(query: string, topK: number = 5, graphDepth: number = 1): string[] {
  if (!currentIndex) {
    throw new Error('No index available. Call buildIndex() or loadIndex() first.')
  }

  const searchResults = searchFiles(query, currentIndex.files)
  const seeds = searchResults.slice(0, topK).map(r => r.file.path)

  if (seeds.length === 0) {
    return []
  }

  const expandedFiles = expandGraphFromSeeds(seeds, currentIndex.graph, graphDepth)

  console.log(`\n=== Graph Expansion ===`)
  console.log(`Seeds: ${seeds.length}`)
  console.log(`Expanded to: ${expandedFiles.length} files\n`)

  return expandedFiles
}

export function getIndex(): RepositoryIndex | null {
  return currentIndex
}

import path from 'path'
import { FileNode, CodeGraph, GraphNode, GraphEdge } from '../types/index.js'

interface ImportResolution {
  fromFile: string
  toFile: string
  importPath: string
}

export function buildDependencyGraph(files: FileNode[]): CodeGraph {
  const nodes: GraphNode[] = []
  const edges: GraphEdge[] = []

  const fileMap = new Map<string, FileNode>()
  files.forEach(file => {
    fileMap.set(file.path, file)
    fileMap.set(normalizeFilePath(file.path), file)
  })

  files.forEach(file => {
    nodes.push({
      id: file.path,
      type: 'file',
      language: file.language,
      path: file.path
    })
  })

  files.forEach(file => {
    if (file.imports.length === 0) return

    const currentDir = path.dirname(file.path)

    for (const importPath of file.imports) {
      const resolvedPath = resolveImport(importPath, currentDir, file.language, fileMap)

      if (resolvedPath && fileMap.has(resolvedPath)) {
        edges.push({
          from: file.path,
          to: resolvedPath,
          type: 'import'
        })
      }
    }
  })

  return { nodes, edges }
}

function resolveImport(
  importPath: string,
  currentDir: string,
  language: string,
  fileMap: Map<string, FileNode>
): string | null {
  if (!importPath.startsWith('.')) {
    return null
  }

  let candidates: string[] = []

  if (language === 'typescript' || language === 'javascript') {
    let cleanPath = importPath
    if (cleanPath.endsWith('.js') || cleanPath.endsWith('.mjs')) {
      cleanPath = cleanPath.replace(/\.(m)?js$/, '')
    }

    const basePath = path.join(currentDir, cleanPath)

    candidates = [
      basePath + '.ts',
      basePath + '.tsx',
      basePath + '.js',
      basePath + '.jsx',
      basePath + '.mjs',
      importPath,
      path.join(basePath, 'index.ts'),
      path.join(basePath, 'index.tsx'),
      path.join(basePath, 'index.js'),
      path.join(basePath, 'index.jsx')
    ]
  } else if (language === 'python') {
    const basePath = path.join(currentDir, importPath.replace(/\./g, '/'))

    candidates = [
      basePath + '.py',
      path.join(basePath, '__init__.py')
    ]
  } else {
    const basePath = path.join(currentDir, importPath)
    candidates = [basePath]
  }

  for (const candidate of candidates) {
    const normalized = normalizeFilePath(candidate)
    if (fileMap.has(normalized)) {
      return fileMap.get(normalized)!.path
    }
  }

  return null
}

function normalizeFilePath(filePath: string): string {
  return filePath.split(path.sep).join('/')
}

export function getFileDependencies(filePath: string, graph: CodeGraph): string[] {
  const dependencies = new Set<string>()

  graph.edges.forEach(edge => {
    if (edge.from === filePath) {
      dependencies.add(edge.to)
    }
  })

  return Array.from(dependencies)
}

export function getFileDependents(filePath: string, graph: CodeGraph): string[] {
  const dependents = new Set<string>()

  graph.edges.forEach(edge => {
    if (edge.to === filePath) {
      dependents.add(edge.from)
    }
  })

  return Array.from(dependents)
}

export function expandGraphFromSeeds(seeds: string[], graph: CodeGraph, maxDepth: number = 2): string[] {
  const result = new Set<string>(seeds)
  const queue: Array<{ path: string; depth: number }> = seeds.map(s => ({ path: s, depth: 0 }))
  const visited = new Set<string>(seeds)

  while (queue.length > 0) {
    const current = queue.shift()!

    if (current.depth >= maxDepth) continue

    graph.edges.forEach(edge => {
      if (edge.from === current.path && !visited.has(edge.to)) {
        result.add(edge.to)
        visited.add(edge.to)
        queue.push({ path: edge.to, depth: current.depth + 1 })
      }

      if (edge.to === current.path && !visited.has(edge.from)) {
        result.add(edge.from)
        visited.add(edge.from)
        queue.push({ path: edge.from, depth: current.depth + 1 })
      }
    })
  }

  return Array.from(result)
}

import { FileNode, RepositoryIndex, IndexStatistics } from '../types/index.js'
import { scanRepository } from '../scanner/fileScanner.js'
import { extractImports } from '../languages/importDetector.js'
import { extractSymbols } from '../languages/symbolExtractor.js'
import { buildDependencyGraph } from '../graph/graphBuilder.js'

export function indexRepository(rootPath: string): RepositoryIndex {
  console.log('Scanning repository...')
  const files = scanRepository(rootPath)
  console.log(`Found ${files.length} files`)

  console.log('Extracting imports and symbols...')
  files.forEach((file, index) => {
    if ((index + 1) % 100 === 0) {
      console.log(`Processed ${index + 1}/${files.length} files`)
    }

    try {
      file.imports = extractImports(file.content, file.language)
      file.symbols = extractSymbols(file.content, file.language)
    } catch (error) {
      console.warn(`Error processing file ${file.path}:`, error)
    }
  })

  console.log('Building dependency graph...')
  const graph = buildDependencyGraph(files)
  console.log(`Graph: ${graph.nodes.length} nodes, ${graph.edges.length} edges`)

  console.log('Computing statistics...')
  const statistics = computeStatistics(files)

  return {
    files,
    graph,
    statistics
  }
}

function computeStatistics(files: FileNode[]): IndexStatistics {
  const languageDistribution: Record<string, number> = {}
  let totalLines = 0
  let symbolCount = 0

  files.forEach(file => {
    languageDistribution[file.language] = (languageDistribution[file.language] || 0) + 1

    const lines = file.content.split('\n').length
    totalLines += lines

    symbolCount += file.symbols.length
  })

  return {
    totalFiles: files.length,
    totalLines,
    languageDistribution,
    symbolCount
  }
}

const IMPORT_PATTERNS: Record<string, RegExp[]> = {
  typescript: [
    /import\s+(?:[\w\s{},*]+\s+from\s+)?['"]([^'"]+)['"]/g,
    /require\s*\(['"]([^'"]+)['"]\)/g,
    /import\s*\(['"]([^'"]+)['"]\)/g,
    /export\s+(?:[\w\s{},*]+\s+from\s+)?['"]([^'"]+)['"]/g
  ],
  javascript: [
    /import\s+(?:[\w\s{},*]+\s+from\s+)?['"]([^'"]+)['"]/g,
    /require\s*\(['"]([^'"]+)['"]\)/g,
    /import\s*\(['"]([^'"]+)['"]\)/g,
    /export\s+(?:[\w\s{},*]+\s+from\s+)?['"]([^'"]+)['"]/g
  ],
  python: [
    /^import\s+([\w.]+)/gm,
    /^from\s+([\w.]+)\s+import/gm
  ],
  java: [
    /import\s+([\w.]+);/g,
    /import\s+static\s+([\w.]+);/g
  ],
  go: [
    /import\s+['"]([^'"]+)['"]/g,
    /import\s+\(([\s\S]*?)\)/g
  ],
  rust: [
    /use\s+([\w:]+)/g,
    /extern\s+crate\s+(\w+)/g
  ],
  cpp: [
    /#include\s+[<"]([^>"]+)[>"]/g
  ],
  c: [
    /#include\s+[<"]([^>"]+)[>"]/g
  ],
  csharp: [
    /using\s+([\w.]+);/g
  ],
  php: [
    /require\s*\(?['"]([^'"]+)['"]\)?;/g,
    /require_once\s*\(?['"]([^'"]+)['"]\)?;/g,
    /include\s*\(?['"]([^'"]+)['"]\)?;/g,
    /include_once\s*\(?['"]([^'"]+)['"]\)?;/g,
    /use\s+([\w\\]+);/g
  ],
  ruby: [
    /require\s+['"]([^'"]+)['"]/g,
    /require_relative\s+['"]([^'"]+)['"]/g
  ],
  kotlin: [
    /import\s+([\w.]+)/g
  ],
  swift: [
    /import\s+(\w+)/g
  ],
  scala: [
    /import\s+([\w.]+)/g
  ]
}

export function extractImports(content: string, language: string): string[] {
  const patterns = IMPORT_PATTERNS[language] || []
  const imports = new Set<string>()

  for (const pattern of patterns) {
    const matches = content.matchAll(pattern)

    for (const match of matches) {
      if (match[1]) {
        let importPath = match[1].trim()

        if (language === 'go' && importPath.includes('\n')) {
          const lines = importPath.split('\n')
          lines.forEach(line => {
            const cleaned = line.trim().replace(/['"]/g, '')
            if (cleaned && !cleaned.startsWith('//')) {
              imports.add(cleaned)
            }
          })
        } else {
          importPath = importPath.split(/\s+/)[0]
          imports.add(importPath)
        }
      }
    }
  }

  return Array.from(imports)
}

export function resolveImportPath(importPath: string, currentFilePath: string, language: string): string | null {
  if (!importPath) return null

  if (importPath.startsWith('.')) {
    return importPath
  }

  if (language === 'typescript' || language === 'javascript') {
    if (!importPath.startsWith('.') && !importPath.startsWith('/')) {
      return null
    }
  }

  return importPath
}

